'use client'

import { api } from "@/api/axios"
import { ISmartphone } from "@/shared/types/smartphone.types";
import { useSmartPhoneStore } from "@/store/smartphone.store";
import { Revalidate } from "next/dist/server/lib/cache-control"
import { SmartPhoneCard } from "./SmartPhoneCard";

export const revalidate: Revalidate = 60;

export async function SmartPhoneList() {
    const smartphonesData = await api.get<ISmartphone[]>("/smartphones");

    const smartphones = useSmartPhoneStore(state => state.smartPhones);
    const setSmartphones = useSmartPhoneStore(state => state.setSmartphones);

    setSmartphones(smartphonesData.data);

    return (
        <>
            {smartphones.map((smartphone: ISmartphone) =>
                <SmartPhoneCard key={smartphone.id}
                id={smartphone.id}
                alt={smartphone.name}
                src={smartphone.imageUrl as string}
                brand={smartphone.brand}
                name={smartphone.name}
                price={smartphone.price}
                 /> 
            )}
        </>
    )
}